local english   = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_EN]
local german    = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_DE]
local french    = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_FR]
local spanish   = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_ES]
local italian   = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_IT]
local japanese  = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_JP]
local russian   = FCOIS.localizationVars.localizationAll[FCOIS_CON_LANG_RU]

--Generate settingsmenu texts for the dynamic icons
function FCOIS.generateLocalizedDynamicIconTexts()
    --Add texts for settings menu (the different languages)

    --Build texts etc. for non-dynamic icons
    for nonDynIconId=1, numNonDynIcons, 1 do
        local iconToOrdinalStrNonDynEn = iconNrToOrdinalStr[1][tonumber(nonDynIconId)] or "th"
        english["options_icon_sort_" .. tostring(nonDynIconId)]	  = tostring(nonDynIconId).. iconToOrdinalStrNonDynEn
        german["options_icon_sort_" .. tostring(nonDynIconId)]    = tostring(nonDynIconId).."."
        french["options_icon_sort_" .. tostring(nonDynIconId)]    = tostring(nonDynIconId).."."
        --Japanese sort is identical to english so the metatable trick is taking care of it
        russian["options_icon_sort_" .. tostring(nonDynIconId)]   = tostring(nonDynIconId) .."-—П –њo–Ј–Є—Ж–Є—П"
    end
    --Build texts etc. for dynamic icons
    local numDynIconsUsable = FCOIS.settingsVars.settings.numMaxDynamicIconsUsable
    for dynIconId=1, numDynIconsUsable, 1 do
        local fcoisDynIconNr = iconId2FCOISIconNr[dynIconId]
        local isDynamic = isDynamicIcon[fcoisDynIconNr]
        local fcoisLockDynMenuIconNr = lockDynMenuEntryNr2FCOISIconId[dynIconId]

        --Non dynamic icon -> Context menu for the filter buttons "lockDyn" with the first entry: Lock icon
        if fcoisLockDynMenuIconNr == FCOIS_CON_ICON_LOCK then
            english["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= english["options_icon1_color"]
            german["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= german["options_icon1_color"]
            french["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= french["options_icon1_color"]
            spanish["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= spanish["options_icon1_color"]
            italian["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= italian["options_icon1_color"]
            japanese["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= japanese["options_icon1_color"]
            russian["filter_lockdyn_" .. tostring(fcoisLockDynMenuIconNr)]				= russian["options_icon1_color"]
        end
        --Dynamic icon and not the first entry of the lockDyn context menu
        if isDynamic then
            local iconToOrdinalStrEn = iconNrToOrdinalStr[1][tonumber(dynIconId)] or "th"
            local iconToOrdinalStrFr = iconNrToOrdinalStr[3][tonumber(dynIconId)] or "."
        --English
            english["options_icon" .. tostring(fcoisDynIconNr).."_TT"]				= "Show tooltip"
            english["options_icon" .. tostring(fcoisDynIconNr).."_tooltip_TT"]		= "Show tooltip at " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic icon"
            english["options_icon" .. tostring(fcoisDynIconNr).."_color"]				= tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["options_icon" .. tostring(fcoisDynIconNr).."_color_TT"]		= "Color for the " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic filter icon"
            english["options_icon" .. tostring(fcoisDynIconNr).."_texture"]				= "Icon"
            english["options_icon" .. tostring(fcoisDynIconNr).."_texture_TT"]		= "Icon for the " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic filter marker"
            english["options_icon" .. tostring(fcoisDynIconNr).."_size"]				= "Size"
            english["options_icon" .. tostring(fcoisDynIconNr).."_size_TT"]		= "Size of the " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic filter icon"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetX"]				= "Offset X"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetX_TT"]		= "Offset X of the " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic filter icon"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetY"]				= "Offset Y"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetY_TT"]		= "Offset Y of the " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic filter icon"
            english["options_icon" .. tostring(fcoisDynIconNr).."_tooltip_text"]		= "Marked as " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["options_icon" .. tostring(fcoisDynIconNr).."_activate_text"]       = "Activate " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["options_icon" .. tostring(fcoisDynIconNr).."_enabled"]				= "Activate " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["options_icon" .. tostring(fcoisDynIconNr).."_enabled_TT"]     = "The " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic icon is enabled and can be used to mark items. If you disable this setting the context menus won't show the entry and you cannot use the icon."
            english["rightclick_menu_mark_dynamic" .. tostring(dynIconId)]     	        = "Mark with " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["rightclick_menu_demark_dynamic" .. tostring(dynIconId)]   	        = "Unmark " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["button_context_menu_mark_all_as_dynamic" .. tostring(dynIconId)]   = "+ " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["button_context_menu_unmark_all_as_dynamic" .. tostring(dynIconId)] = "- " .. tostring(dynIconId) .. iconToOrdinalStrEn .. " dynamic"
            english["options_icon_sort_" .. tostring(fcoisDynIconNr)]				    = tostring(fcoisDynIconNr).. iconToOrdinalStrEn
            english["SI_BINDING_NAME_FCOIS_MARK_ITEM_" .. tostring(fcoisDynIconNr)]  	= "Mark with dynamic icon " .. tostring(dynIconId)
        --German
            german["options_icon" .. tostring(fcoisDynIconNr).."_TT"]				= "Zeige Tooltip"
            german["options_icon" .. tostring(fcoisDynIconNr).."_tooltip_TT"]		= "Zeige Tooltip am " .. tostring(dynIconId) .. ". dynamischen Symbols"
            german["options_icon" .. tostring(fcoisDynIconNr).."_color"]				= tostring(dynIconId) .. ". dynamische"
            german["options_icon" .. tostring(fcoisDynIconNr).."_color_TT"]		= "Farbe des " .. tostring(dynIconId) .. ". dynamischen Filter Symbols"
            german["options_icon" .. tostring(fcoisDynIconNr).."_texture"]				= "Symbol"
            german["options_icon" .. tostring(fcoisDynIconNr).."_texture_TT"]		= "Symbol der " .. tostring(dynIconId) .. ". dynamischen Filter Markierung"
            german["options_icon" .. tostring(fcoisDynIconNr).."_size"]				    = "Gr√ґ√Яe"
            german["options_icon" .. tostring(fcoisDynIconNr).."_size_TT"]		    = "Gr√ґ√Яe des " .. tostring(dynIconId) .. ". dynamischen Filter Symbols"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetX"]				= "Abstand X"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetX_TT"]		= "Abstand der position auf der X-Achse des " .. tostring(dynIconId) .. ". dynamischen Filter Markierungssymbols"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetY"]				= "Abstand Y"
            english["options_icon" .. tostring(fcoisDynIconNr).."_offsetY_TT"]		= "Abstand der Position auf der Y-Achse des " .. tostring(dynIconId) .. ". dynamischen Filter Markierungssymbols"
            german["options_icon" .. tostring(fcoisDynIconNr).."_tooltip_text"]		    = "Markiert mit " .. tostring(dynIconId) .. ". dynamischen"
            german["options_icon" .. tostring(fcoisDynIconNr).."_activate_text"]        = "Aktiviere " .. tostring(dynIconId) .. ". dynamische"
            german["options_icon" .. tostring(fcoisDynIconNr).."_enabled"]				= tostring(dynIconId) .. ". dynamische aktivieren"
            german["options_icon" .. tostring(fcoisDynIconNr).."_enabled_TT"]      = "Das " .. tostring(dynIconId) .. ". dynamische Symbol ist aktiviert und kann zum Markieren von Gegenst√§nden verwendet werden. Wenn du diese Option deaktivierst kann dieses Symbol nicht verwendet werden und das Kontextmen√Љ zeigt dir das Symbol nicht zur Auswahl an."
            german["rightclick_menu_mark_dynamic" .. tostring(dynIconId)]     	        = "Markiere mit " .. tostring(dynIconId) .. ". dynamischen"
            german["rightclick_menu_demark_dynamic" .. tostring(dynIconId)]   	        = "Entferne Markierung vom " .. tostring(dynIconId) .. ". dynamischen"
            german["button_context_menu_mark_all_as_dynamic" .. tostring(dynIconId)]    = "+ " .. tostring(dynIconId) .. ". dynamische"
            german["button_context_menu_unmark_all_as_dynamic" .. tostring(dynIconId)]  = "- " .. tostring(dynIconId) .. ". dynamische"
            german["options_icon_sort_" .. tostring(fcoisDynIconNr)]				    = tostring(fcoisDynIconNr).."."
            german["SI_BINDING_NAME_FCOIS_MARK_ITEM_" .. tostring(fcoisDynIconNr)]  	= "Markiere mit dynamischen Symbol " .. tostring(dynIconId)
